const MIN_SCORE = 70;
const BATCH = 5;

const ALLOW_SEGMENTS = new Set([
  'noxh_income', 'valuation', 'sme_credit', 'general_inbound',
]);

function parseMeta(raw) {
  if (!raw) return {};
  try {
    return typeof raw === 'string' ? JSON.parse(raw) : raw;
  } catch {
    return {};
  }
}

const res = $input.first().json;
const rows = Array.isArray(res.values) ? res.values : [];
if (rows.length < 2) {
  return [{ json: { empty: true, message: 'content_queue trống' } }];
}

const headers = rows[0].map((x) => String(x ?? '').trim().toLowerCase());
const out = [];

for (let i = 1; i < rows.length; i++) {
  const cells = rows[i];
  if (!cells?.some((c) => String(c ?? '').trim())) continue;

  const row = { sheet_row: i + 1 };
  headers.forEach((key, j) => {
    if (key) row[key] = cells[j] ?? '';
  });

  const segment = String(row.segment || '').trim().toLowerCase();
  const score = Number(row.score || 0);
  const status = String(row.status || '').trim().toLowerCase();
  const meta = parseMeta(row.meta);

  if (meta.draft_created === true) continue;
  if (!ALLOW_SEGMENTS.has(segment)) continue;
  if (score < MIN_SCORE) continue;
  if (status !== 'classified' && row.claude_verdict !== 'qualified') continue;

  const text = String(row.text || '').trim();
  if (text.length < 20) continue;

  out.push({ json: row });
  if (out.length >= BATCH) break;
}

if (!out.length) {
  return [{ json: { empty: true, message: 'Không còn candidate draft (score≥70, classified, chưa draft)' } }];
}

return out;

const data = $getWorkflowStaticData('global');
data.a3_stats = { draft_ok: 0, draft_fail: 0, l0_fail: 0, parse_fail: 0 };
return $input.all();

const row = $('Loop Draft Candidates').item?.json || $input.first().json;

const system = `Growth Copywriter Magnix — Value-First Hook.
[/matrix] [/artifacts] [/deconstruct]
Chỉ trả JSON hợp lệ, không markdown bọc ngoài:
{"title":"","hook_line":"","segment":"","artifact_markdown":"","source_refs":[],"cta_opt_in":"","disclaimer":"","export_hint":"pdf|excel|both"}
- hook_line ≤25 từ
- artifact_markdown: ≥1 bảng Markdown so sánh
- Không cam kết lãi suất cụ thể, không hứa duyệt vay`;

const segment = String(row.segment || 'general_inbound');
const pain = String(row.text || '').slice(0, 2000);
const assetMap = {
  noxh_income: 'checklist_ho_so_noxh',
  valuation: 'checklist_tham_dinh',
  sme_credit: 'checklist_vay_dn',
  general_inbound: 'checklist_mua_nha',
};
const userPayload = JSON.stringify({
  segment,
  pain,
  asset_type: assetMap[segment] || 'checklist',
  angle: 'pain_from_social_listen',
  reference_url_or_text: String(row.post_url || '').slice(0, 500),
  requires_legal_qa: ['noxh_income', 'valuation', 'sme_credit'].includes(segment),
  interest_key: row.interest_key || '',
  source_normalized_key: row.normalized_key,
});

try {
  if ($env.DEEPSEEK_API_KEY) {
    const res = await this.helpers.httpRequest({
      method: 'POST',
      url: $env.DEEPSEEK_API_URL || 'https://api.deepseek.com/chat/completions',
      headers: {
        Authorization: `Bearer ${$env.DEEPSEEK_API_KEY}`,
        'Content-Type': 'application/json',
      },
      body: {
        model: $env.DEEPSEEK_MODEL || 'deepseek-chat',
        temperature: 0.4,
        max_tokens: 4096,
        response_format: { type: 'json_object' },
        messages: [
          { role: 'system', content: system },
          { role: 'user', content: userPayload },
        ],
      },
      json: true,
    });
    return [{ json: res }];
  }

  if ($env.ANTHROPIC_API_KEY) {
    const model = $env.ANTHROPIC_DRAFT_MODEL || 'claude-sonnet-4-6';
    const res = await this.helpers.httpRequest({
      method: 'POST',
      url: 'https://api.anthropic.com/v1/messages',
      headers: {
        'x-api-key': $env.ANTHROPIC_API_KEY,
        'anthropic-version': '2023-06-01',
        'Content-Type': 'application/json',
      },
      body: {
        model,
        max_tokens: 4096,
        temperature: 0.4,
        system,
        messages: [{ role: 'user', content: userPayload }],
      },
      json: true,
    });
    return [{ json: res }];
  }

  throw new Error('Thiếu DEEPSEEK_API_KEY hoặc ANTHROPIC_API_KEY');
} catch (e) {
  return [{ json: { error: true, message: e.message } }];
}

function extractJsonString(raw) {
  if (raw == null) throw new Error('EMPTY_LLM_OUTPUT');
  const s = typeof raw === 'string' ? raw : JSON.stringify(raw);
  const fenced = s.match(/```(?:json)?\s*([\s\S]*?)```/i);
  return (fenced ? fenced[1] : s).trim();
}

const res = $input.first().json;
const raw =
  res.choices?.[0]?.message?.content ??
  res.content?.[0]?.text ??
  res.message?.content ??
  res;

try {
  const parsed = JSON.parse(extractJsonString(raw));
  const required = ['title', 'hook_line', 'segment', 'artifact_markdown', 'cta_opt_in'];
  for (const k of required) {
    if (!parsed[k] || !String(parsed[k]).trim()) throw new Error(`MISSING_${k.toUpperCase()}`);
  }
  if (!Array.isArray(parsed.source_refs)) parsed.source_refs = [];
  return [{
    json: {
      ok: true,
      draft: {
        title: String(parsed.title).slice(0, 500),
        hook_line: String(parsed.hook_line).slice(0, 500),
        segment: String(parsed.segment),
        artifact_markdown: String(parsed.artifact_markdown).slice(0, 45000),
        source_refs: parsed.source_refs.map(String).slice(0, 10),
        cta_opt_in: String(parsed.cta_opt_in).slice(0, 1000),
        disclaimer: String(parsed.disclaimer || '').slice(0, 2000),
        export_hint: String(parsed.export_hint || 'pdf'),
      },
    },
  }];
} catch (e) {
  return [{ json: { ok: false, parse_error: e.message, raw_preview: String(raw).slice(0, 200) } }];
}

const FORBIDDEN = [
  /cam kết.*duyệt/i,
  /lãi suất\s*\d+([.,]\d+)?\s*%/i,
  /đảm bảo.*(vay|duyệt)/i,
  /100%\s*(thành công|duyệt)/i,
];

const item = $input.first().json;
if (!item.ok || !item.draft) {
  return [{ json: { ...item, l0_pass: false } }];
}

const text = [
  item.draft.title,
  item.draft.hook_line,
  item.draft.artifact_markdown,
  item.draft.cta_opt_in,
  item.draft.disclaimer,
].join('\n');

const hits = FORBIDDEN.filter((re) => re.test(text)).map((re) => re.source);
if (hits.length) {
  return [{
    json: {
      ok: false,
      l0_pass: false,
      l0_hits: hits,
      error: 'L0_FORBIDDEN',
    },
  }];
}

return [{ json: { ...item, l0_pass: true, l0_hits: [] } }];

const source = $('Loop Draft Candidates').item?.json || {};
const item = $input.first().json;

if (!item.ok || !item.draft) {
  return [{ json: { ok: false, error: 'MERGE_SKIP', sheet_row: source.sheet_row } }];
}

const d = item.draft;
const meta = JSON.stringify({
  source_refs: d.source_refs,
  l0_hits: item.l0_hits || [],
  agent: 'agent-3',
  source_post_url: source.post_url,
  created_at: new Date().toISOString(),
}).slice(0, 50000);

return [{
  json: {
    ok: true,
    source_normalized_key: source.normalized_key,
    queue_sheet_row: source.sheet_row,
    append_row: [
      String(source.normalized_key || ''),
      String(source.post_id || ''),
      String(d.segment || source.segment || ''),
      d.title,
      d.hook_line,
      d.artifact_markdown,
      d.cta_opt_in,
      d.disclaimer,
      d.export_hint,
      'draft',
      'L0',
      new Date().toISOString(),
      'agent3_lead_magnet',
      meta,
    ],
    queue_meta_patch: {
      draft_created: true,
      draft_status: 'draft',
      draft_title: d.title,
      draft_at: new Date().toISOString(),
    },
  },
}];

const SHEET_ID = '1fYB4h_BTiKXa9O3lBah-tQonWpQOQMG2aSkSfPs6yU4';
const TAB = 'content_drafts';

const item = $input.first().json;
if (!item.ok || !item.append_row) {
  return [{ json: { ok: false, error: 'SKIP_APPEND' } }];
}

await this.helpers.httpRequestWithAuthentication.call(this, 'googleApi', {
  method: 'POST',
  url: `https://sheets.googleapis.com/v4/spreadsheets/${SHEET_ID}/values/${encodeURIComponent(`${TAB}!A:N`)}:append?valueInputOption=USER_ENTERED&insertDataOption=INSERT_ROWS`,
  body: { values: [item.append_row] },
  json: true,
});

const data = $getWorkflowStaticData('global');
if (!data.a3_stats) data.a3_stats = { draft_ok: 0, draft_fail: 0, l0_fail: 0 };
data.a3_stats.draft_ok += 1;

return [{ json: { ok: true, storage: 'content_drafts', normalized_key: item.source_normalized_key } }];

const SHEET_ID = '1fYB4h_BTiKXa9O3lBah-tQonWpQOQMG2aSkSfPs6yU4';
const TAB = 'content_queue';

const merge = $('Merge Draft Row').item?.json || $input.first().json;
if (!merge.queue_sheet_row || !merge.queue_meta_patch) {
  return [{ json: { ok: false, skip: true } }];
}

const row = merge.queue_sheet_row;
let existing = {};
try {
  const getRes = await this.helpers.httpRequestWithAuthentication.call(this, 'googleApi', {
    method: 'GET',
    url: `https://sheets.googleapis.com/v4/spreadsheets/${SHEET_ID}/values/${encodeURIComponent(`${TAB}!O${row}`)}`,
    json: true,
  });
  const cell = getRes.values?.[0]?.[0];
  if (cell) existing = JSON.parse(cell);
} catch {
  existing = {};
}

const meta = JSON.stringify({ ...existing, ...merge.queue_meta_patch }).slice(0, 50000);

await this.helpers.httpRequestWithAuthentication.call(this, 'googleApi', {
  method: 'PUT',
  url: `https://sheets.googleapis.com/v4/spreadsheets/${SHEET_ID}/values/${encodeURIComponent(`${TAB}!O${row}`)}?valueInputOption=USER_ENTERED`,
  body: { values: [[meta]] },
  json: true,
});

return [{ json: { ok: true, queue_row_updated: row } }];

const data = $getWorkflowStaticData('global');
if (!data.a3_stats) data.a3_stats = {};
data.a3_stats.l0_fail = (data.a3_stats.l0_fail || 0) + 1;
return $input.all();

const data = $getWorkflowStaticData('global');
if (!data.a3_stats) data.a3_stats = {};
data.a3_stats.parse_fail = (data.a3_stats.parse_fail || 0) + 1;
return $input.all();

const data = $getWorkflowStaticData('global');
const stats = data.a3_stats || {};
return [{ json: {
  ok: true,
  workflow: 'content-draft',
  stats,
  batch_size: 5,
  hint: (stats.draft_ok || 0) === 0 ? 'Không draft mới — hết candidate hoặc lỗi LLM/L0' : null,
  finished_at: new Date().toISOString(),
}}];
